class StatDelta {
  final StatType type;
  final int delta;

  const StatDelta(this.type, this.delta);
}

class StatItem {
  final StatType type;
  final int value;
  final int initialRank; // 0, 1, 2, 3

  const StatItem({
    required this.type,
    required this.value,
    required this.initialRank,
  });

  StatItem copyWith({int? value, int? initialRank}) {
    return StatItem(
      type: type,
      value: value ?? this.value,
      initialRank: initialRank ?? this.initialRank,
    );
  }
}
